mapper.select:
SELECT PRIORITY AS groupKey, COUNT(*) AS count FROM TASK WHERE STATUS <> 'DELETED' AND USER_ID = #{userId} AND DUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD') AND DUE_DATE < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
AND CATEGORY_ID = #{categoryId}
GROUP BY PRIORITY ORDER BY COUNT(*) DESC
